main();

function main()
{
    const selections = instanceList_ElementTable.GetMultipleSelectionRow();
    if(selections.length == 0)
    {
        _showMessage("请选择实例", "warning");
        return;
    }
    $Variable.deleteInstances = [...selections];
}


function _showMessage(massage, type = "error")
{
    const options = {
        message: massage,
        type: type,
        duration: 3000,
        showClose: true,
    };
    ShowMessage(options);
}

