linkList.script:
const COMMAND_AND_SIGNAL = {
    "1": "importInstanceTreeSignal",
    "2": "importTagsSignal",
    "3": "exportInstancesSignal",
    "4": "moveInstanceSignal",
    "5": "submitInstancesSignal"
};


console.log("-I- 下拉菜单 Command 事件：args = ", arguments);
const command = arguments[1];

main();

function main()
{
    if(!Object.hasOwn(COMMAND_AND_SIGNAL, `${command}`)){
        return;
    }

    const signalName = COMMAND_AND_SIGNAL[`${command}`];

    $Variable[signalName] = !$Variable[signalName];
}

